import { Component } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { PortfolioService } from '../../core/services/portfolio.service';

@Component({
  selector: 'app-contact',
  templateUrl: './contact.component.html',
  styleUrls: ['./contact.component.scss']
})
export class ContactComponent {
  form: FormGroup;
  submitting = false;
  submitted = false;
  errorMessage = '';

  constructor(private fb: FormBuilder, private portfolioService: PortfolioService) {
    this.form = this.fb.group({
      name: ['', Validators.required],
      email: ['', [Validators.required, Validators.email]],
      message: ['', Validators.required]
    });
  }

  submit() {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }
    this.submitting = true;
    this.errorMessage = '';

    this.portfolioService.submitContact(this.form.value).subscribe(result => {
      this.submitting = false;
      if ('error' in result) {
        this.errorMessage = result.error;
      } else {
        this.submitted = true;
        this.form.reset();
      }
    });
  }
}
<section class="section">
  <div class="container contact">
    <span class="term-label">mail -s "hello" joyce</span>
    <h1>Contact</h1>

    <div class="contact__channels">
      <a href="https://linkedin.com/in/joyce-coem" target="_blank" rel="noopener" class="btn">LinkedIn</a>
      <a href="https://github.com/JoyceCoem" target="_blank" rel="noopener" class="btn">GitHub</a>
      <a href="https://medium.com/@joycecoem05" target="_blank" rel="noopener" class="btn">Medium</a>
      <a href="mailto:joycecoem05@gmail.com" class="btn">joycecoem05&#64;gmail.com</a>
    </div>

    <form [formGroup]="form" (ngSubmit)="submit()" class="contact__form" *ngIf="!submitted">
      <label for="name">Name</label>
      <input id="name" type="text" formControlName="name">

      <label for="email">Email</label>
      <input id="email" type="email" formControlName="email">

      <label for="message">Message</label>
      <textarea id="message" rows="5" formControlName="message"></textarea>

      <p class="contact__error" *ngIf="errorMessage">{{ errorMessage }}</p>

      <button type="submit" class="btn btn--solid" [disabled]="submitting">
        {{ submitting ? 'Sending...' : 'Send Message' }}
      </button>
    </form>

    <p class="contact__success" *ngIf="submitted">
      Thanks for reaching out — I'll get back to you soon. In the meantime, feel free to connect on LinkedIn too.
    </p>
  </div>
</section>
